import Link from "next/link";
import { headers } from "next/headers";
import { redirect } from "next/navigation";
import prisma from "@/shared/lib/db/prisma";
import { getMongoDb } from "@/shared/lib/db/mongo-client";
import { getAppDbProvider } from "@/shared/lib/db/app-db-provider";
import { productService } from "@/features/products/server";
import { ProductCard } from "@/features/products";
import type { ProductWithImages } from "@/features/products";
import { getCmsRepository } from "@/features/cms/services/cms-repository";
import { getCmsThemeSettings } from "@/features/cms/services/cms-theme-settings";
import { getCmsMenuSettings } from "@/features/cms/services/cms-menu-settings";
import { CmsPageRenderer } from "@/features/cms/components/frontend/CmsPageRenderer";
import { CmsPageShell } from "@/features/cms/components/frontend/CmsPageShell";
import type { Slug } from "@/features/cms/types";
import { getSlugsForDomain, resolveCmsDomainByHost } from "@/features/cms/services/cms-domain";
import { buildColorSchemeMap, type ThemeSettings } from "@/features/cms/types/theme-settings";
import { getMediaInlineStyles, getMediaStyleVars } from "@/features/cms/components/frontend/theme-styles";
import { auth } from "@/features/auth/auth";
import type { Session } from "next-auth";
import { getUserPreferences } from "@/features/auth/server";
import { Facebook, Instagram, Linkedin, Twitter, Youtube } from "lucide-react";

const isAdminSession = (session: Session | null): boolean => {
  if (!session?.user) return false;
  const user = session.user as Session["user"] & { isElevated?: boolean; role?: string | null };
  if (user.isElevated) return true;
  const role = user.role ?? "";
  return ["admin", "super_admin", "superuser"].includes(role);
};

const canPreviewDrafts = async (
  session: Session | null
): Promise<boolean> => {
  if (!isAdminSession(session)) return false;
  const userId = session?.user?.id;
  if (!userId) return false;
  try {
    const prefs = await getUserPreferences(userId);
    return prefs.cmsPreviewEnabled === true;
  } catch {
    return false;
  }
};

export const dynamic = "force-dynamic";

const notNull = <T,>(value: T | null | undefined): value is T => value != null;
const FRONT_PAGE_SETTING_KEY = "front_page_app";
const FRONT_PAGE_ALLOWED = new Set(["products", "chatbot", "notes"]);

type SettingDocument = {
  _id: string;
  key?: string;
  value?: string;
};

const canUsePrismaSettings = (): boolean =>
  Boolean(process.env.DATABASE_URL) && "setting" in prisma;

const readMongoFrontPageSetting = async (): Promise<string | null> => {
  if (!process.env.MONGODB_URI) return null;
  try {
    const mongo = await getMongoDb();
    const doc = await mongo
      .collection<SettingDocument>("settings")
      .findOne({ _id: FRONT_PAGE_SETTING_KEY });
    if (doc?.value) return doc.value;
  } catch {
    // Mongo unavailable — ignore.
  }
  return null;
};

const readPrismaFrontPageSetting = async (): Promise<string | null> => {
  if (!canUsePrismaSettings()) return null;
  try {
    const setting = await prisma.setting.findUnique({
      where: { key: FRONT_PAGE_SETTING_KEY },
      select: { value: true },
    });
    if (setting?.value) return setting.value;
  } catch {
    // Prisma unavailable — ignore.
  }
  return null;
};

const getFrontPageSetting = async (): Promise<string | null> => {
  const provider = await getAppDbProvider();
  if (provider === "mongodb") {
    const mongoValue = await readMongoFrontPageSetting();
    if (mongoValue) return mongoValue;
    return readPrismaFrontPageSetting();
  }

  const prismaValue = await readPrismaFrontPageSetting();
  if (prismaValue) return prismaValue;
  return readMongoFrontPageSetting();
};

export default async function Home() {
  const [frontPageApp, cmsRepository] = await Promise.all([
    getFrontPageSetting(),
    getCmsRepository(),
  ]);

  if (frontPageApp && FRONT_PAGE_ALLOWED.has(frontPageApp)) {
    if (frontPageApp === "chatbot") {
      redirect("/admin/chatbot");
    }
    if (frontPageApp === "notes") {
      redirect("/admin/notes");
    }
  }

  const hdrs = await headers();
  const domain = await resolveCmsDomainFromHeaders(hdrs);
  const [slugs, themeSettings, menuSettings] = await Promise.all([
    getSlugsForDomain(domain.id, cmsRepository),
    getCmsThemeSettings(),
    getCmsMenuSettings(domain.id),
  ]);
  const defaultSlug = slugs.find((s: Slug) => !!s.isDefault);
  const colorSchemes = buildColorSchemeMap(themeSettings);

  type MaybeImages = {
    images?: (ProductWithImages["images"][number] | null)[] | null;
    catalogs?: (ProductWithImages["catalogs"][number] | null)[] | null;
  };

  const normalizeProduct = (
    p: ProductWithImages | (ProductWithImages & MaybeImages)
  ): ProductWithImages => {
    return {
      ...p,
      images: Array.isArray(p.images) ? p.images.filter(notNull) : [],
      catalogs: Array.isArray(p.catalogs) ? p.catalogs.filter(notNull) : [],
    };
  };

  if (defaultSlug) {
    // Try to load the published CMS page linked to this slug
    const [cmsPage, session] = await Promise.all([
      cmsRepository.getPageBySlug(defaultSlug.slug),
      auth(),
    ]);
    const allowDrafts = await canPreviewDrafts(session);
    const hasCmsContent = cmsPage && (allowDrafts || cmsPage.status === "published") && cmsPage.components.length > 0;

    const showMenu = cmsPage?.showMenu !== false;
    return (
      <CmsPageShell
        menu={menuSettings}
        theme={themeSettings}
        colorSchemes={colorSchemes}
        showMenu={showMenu}
      >
        {hasCmsContent ? (
          <CmsPageRenderer
            components={cmsPage.components}
            colorSchemes={colorSchemes}
            layout={{ fullWidth: themeSettings.fullWidth }}
            hoverEffect={themeSettings?.enableAnimations ? themeSettings.hoverEffect : undefined}
            hoverScale={themeSettings?.enableAnimations ? themeSettings.hoverScale : undefined}
            mediaVars={getMediaStyleVars(themeSettings)}
            mediaStyles={getMediaInlineStyles(themeSettings)}
          />
        ) : (
          <section className="w-full py-12">
            <div className="container px-4 md:px-6">
              <h1 className="text-3xl font-bold">
                Welcome to {defaultSlug.slug}
              </h1>
            </div>
          </section>
        )}
      </CmsPageShell>
    );
  }

  const productsRaw = await productService.getProducts({});
  const products = (
    productsRaw as (ProductWithImages | (ProductWithImages & MaybeImages))[]
  ).map(normalizeProduct);

  const showFallbackHeader = !menuSettings.showMenu;
  return (
    <CmsPageShell
      menu={menuSettings}
      theme={themeSettings}
      colorSchemes={colorSchemes}
      showMenu={menuSettings.showMenu}
    >
      <div className="flex min-h-screen flex-col">
        {showFallbackHeader ? (
          <header className="flex h-14 items-center px-4 lg:px-6">
            <Link
              href="#"
              className="flex items-center justify-center"
              prefetch={false}
            >
              <MountainIcon className="size-6" />
              <span className="sr-only">Acme Inc</span>
            </Link>
            <nav className="ml-auto flex gap-4 sm:gap-6">
              <Link
                href="/admin"
                className="text-sm font-medium underline-offset-4 hover:underline"
                prefetch={false}
              >
                Admin
              </Link>
            </nav>
          </header>
        ) : null}

        <div className="flex-1">
          <section className="w-full py-12">
            <div className="container px-4 md:px-6">
              <div className="grid grid-cols-1 gap-6 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
                {products.map((product: ProductWithImages) => (
                  <ProductCard key={product.id} product={product} />
                ))}
              </div>
            </div>
          </section>
        </div>

        {showFallbackHeader ? (
          <footer className="flex w-full shrink-0 flex-col items-center gap-3 border-t border-gray-800 px-4 py-6 sm:flex-row md:px-6">
            <p className="text-xs text-gray-400">
              &copy; 2024 Acme Inc. All rights reserved.
            </p>
            <div className="flex flex-col items-center gap-3 sm:ml-auto sm:flex-row sm:items-center">
              <nav className="flex gap-4 sm:gap-6">
                <Link
                  href="#"
                  className="text-xs underline-offset-4 hover:underline"
                  prefetch={false}
                >
                  Terms of Service
                </Link>
                <Link
                  href="#"
                  className="text-xs underline-offset-4 hover:underline"
                  prefetch={false}
                >
                  Privacy
                </Link>
              </nav>
              <SocialLinks theme={themeSettings} />
            </div>
          </footer>
        ) : null}
      </div>
    </CmsPageShell>
  );
}

function MountainIcon(props: React.SVGProps<SVGSVGElement>) {
  return (
    <svg
      {...props}
      xmlns="http://www.w3.org/2000/svg"
      width="24"
      height="24"
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
    >
      <path d="m8 3 4 8 5-5 5 15H2L8 3z" />
    </svg>
  );
}

type SocialLink = {
  id: string;
  label: string;
  href: string;
  Icon?: React.ComponentType<React.SVGProps<SVGSVGElement>>;
  fallback: string;
};

const normalizeSocialUrl = (value?: string | null): string | null => {
  if (!value) return null;
  const trimmed = value.trim();
  if (!trimmed) return null;
  if (/^https?:\/\//i.test(trimmed)) return trimmed;
  return `https://${trimmed}`;
};

const buildSocialLinks = (theme: ThemeSettings | null | undefined): SocialLink[] => {
  if (!theme) return [];
  const links: SocialLink[] = [];
  const addLink = (link: Omit<SocialLink, "href"> & { href: string | null }) => {
    if (link.href) links.push({ ...link, href: link.href });
  };

  addLink({
    id: "facebook",
    label: "Facebook",
    href: normalizeSocialUrl(theme.socialFacebook),
    Icon: Facebook,
    fallback: "Fb",
  });
  addLink({
    id: "instagram",
    label: "Instagram",
    href: normalizeSocialUrl(theme.socialInstagram),
    Icon: Instagram,
    fallback: "Ig",
  });
  addLink({
    id: "youtube",
    label: "YouTube",
    href: normalizeSocialUrl(theme.socialYoutube),
    Icon: Youtube,
    fallback: "Yt",
  });
  addLink({
    id: "tiktok",
    label: "TikTok",
    href: normalizeSocialUrl(theme.socialTiktok),
    fallback: "TT",
  });
  addLink({
    id: "twitter",
    label: "X / Twitter",
    href: normalizeSocialUrl(theme.socialTwitter),
    Icon: Twitter,
    fallback: "X",
  });
  addLink({
    id: "snapchat",
    label: "Snapchat",
    href: normalizeSocialUrl(theme.socialSnapchat),
    fallback: "SC",
  });
  addLink({
    id: "pinterest",
    label: "Pinterest",
    href: normalizeSocialUrl(theme.socialPinterest),
    fallback: "P",
  });
  addLink({
    id: "tumblr",
    label: "Tumblr",
    href: normalizeSocialUrl(theme.socialTumblr),
    fallback: "T",
  });
  addLink({
    id: "vimeo",
    label: "Vimeo",
    href: normalizeSocialUrl(theme.socialVimeo),
    fallback: "V",
  });
  addLink({
    id: "linkedin",
    label: "LinkedIn",
    href: normalizeSocialUrl(theme.socialLinkedin),
    Icon: Linkedin,
    fallback: "In",
  });

  return links;
};

function SocialLinks({ theme }: { theme: ThemeSettings | null | undefined }) {
  const links = buildSocialLinks(theme);
  if (!links.length) return null;

  return (
    <nav className="flex items-center gap-2" aria-label="Social media">
      {links.map((link) => {
        const Icon = link.Icon;
        return (
          <a
            key={link.id}
            href={link.href}
            className="inline-flex size-8 items-center justify-center rounded-full border border-gray-800 text-gray-400 transition hover:border-gray-600 hover:text-gray-100"
            target="_blank"
            rel="noreferrer"
            aria-label={link.label}
          >
            {Icon ? (
              <Icon className="size-4" aria-hidden="true" />
            ) : (
              <span className="text-[10px] font-semibold" aria-hidden="true">
                {link.fallback}
              </span>
            )}
            <span className="sr-only">{link.label}</span>
          </a>
        );
      })}
    </nav>
  );
}

"use client";

import React, { useCallback, useEffect, useMemo, useRef, useState } from "react";
import type { AiNode, Edge, NodeDefinition } from "@/features/ai/ai-paths/lib";
import {
  CANVAS_HEIGHT,
  CANVAS_WIDTH,
  NODE_MIN_HEIGHT,
  NODE_WIDTH,
  VIEW_MARGIN,
  clampScale,
  clampTranslate,
  getDefaultConfigForType,
  getPortOffsetY,
  sanitizeEdges,
  validateConnection,
} from "@/features/ai/ai-paths/lib";
import { ToastFn } from "@/shared/types/ai-paths-runtime";
import { DRAG_KEYS, getFirstDragValue, setDragData } from "@/shared/utils/drag-drop";

type UseAiPathsCanvasInteractionsArgs = {
  nodes: AiNode[];
  setNodes: React.Dispatch<React.SetStateAction<AiNode[]>>;
  edges: Edge[];
  setEdges: React.Dispatch<React.SetStateAction<Edge[]>>;
  isPathLocked: boolean;
  selectedNodeId: string | null;
  setSelectedNodeId: (value: string | null) => void;
  clearRuntimeInputsForEdges: (removed: Edge[], remaining: Edge[]) => void;
  reportAiPathsError: (error: unknown, context: Record<string, unknown>, fallbackMessage?: string) => void;
  toast: ToastFn;
};

type ConnectingState = {
  fromNodeId: string;
  fromPort: string;
  start: { x: number; y: number };
};

export interface AiPathsCanvasInteractions {
  viewportRef: React.RefObject<HTMLDivElement | null>;
  canvasRef: React.RefObject<HTMLDivElement | null>;
  view: { x: number; y: number; scale: number };
  panState: { startX: number; startY: number; originX: number; originY: number } | null;
  dragState: { nodeId: string; offsetX: number; offsetY: number } | null;
  connecting: ConnectingState | null;
  connectingPos: { x: number; y: number } | null;
  lastDrop: { x: number; y: number } | null;
  selectedEdgeId: string | null;
  edgePaths: { id: string; path: string; label?: string | undefined; arrow?: { x: number; y: number; angle: number } | undefined }[];
  connectingFromNode: AiNode | null;
  ensureNodeVisible: (node: AiNode) => void;
  getCanvasCenterPosition: () => { x: number; y: number };
  handlePointerDown: (event: React.PointerEvent<HTMLDivElement>, nodeId: string) => void;
  handlePointerMove: (event: React.PointerEvent<HTMLDivElement>, nodeId: string) => void;
  handlePointerUp: (event: React.PointerEvent<HTMLDivElement>, nodeId: string) => void;
  handleDragStart: (event: React.DragEvent<HTMLDivElement>, node: NodeDefinition) => void;
  handleDrop: (event: React.DragEvent<HTMLDivElement>) => void;
  handleDragOver: (event: React.DragEvent<HTMLDivElement>) => void;
  handleStartConnection: (event: React.PointerEvent<HTMLButtonElement>, node: AiNode, port: string) => void;
  handleCompleteConnection: (event: React.PointerEvent<HTMLButtonElement>, node: AiNode, port: string) => void;
  handlePanStart: (event: React.PointerEvent<HTMLDivElement>) => void;
  handlePanMove: (event: React.PointerEvent<HTMLDivElement>) => void;
  handlePanEnd: (event: React.PointerEvent<HTMLDivElement>) => void;
  handleReconnectInput: (event: React.PointerEvent<HTMLButtonElement>, nodeId: string, port: string) => void;
  handleRemoveEdge: (edgeId: string) => void;
  handleDisconnectPort: (direction: "input" | "output", nodeId: string, port: string) => void;
  handleDeleteSelectedNode: () => void;
  handleSelectEdge: (edgeId: string | null) => void;
  handleSelectNode: (nodeId: string) => void;
  zoomTo: (targetScale: number) => void;
  fitToNodes: () => void;
  resetView: () => void;
}

export function useAiPathsCanvasInteractions({
  nodes,
  setNodes,
  edges,
  setEdges,
  isPathLocked,
  selectedNodeId,
  setSelectedNodeId,
  clearRuntimeInputsForEdges,
  reportAiPathsError,
  toast,
}: UseAiPathsCanvasInteractionsArgs): AiPathsCanvasInteractions {
  // Initial view centered on the middle of the canvas where nodes are placed
  const [view, setView] = useState({ x: -600, y: -320, scale: 1 });
  const [connecting, setConnecting] = useState<ConnectingState | null>(null);
  const [connectingPos, setConnectingPos] = useState<{ x: number; y: number } | null>(
    null
  );
  const [lastDrop, setLastDrop] = useState<{ x: number; y: number } | null>(null);
  const [dragState, setDragState] = useState<{
    nodeId: string;
    offsetX: number;
    offsetY: number;
  } | null>(null);
  const [panState, setPanState] = useState<{
    startX: number;
    startY: number;
    originX: number;
    originY: number;
  } | null>(null);
  const [selectedEdgeId, setSelectedEdgeId] = useState<string | null>(null);

  const viewportRef = useRef<HTMLDivElement | null>(null);
  const canvasRef = useRef<HTMLDivElement | null>(null);
  const pendingDragRef = useRef<{ nodeId: string; x: number; y: number } | null>(null);
  const rafIdRef = useRef<number | null>(null);
  const lastDropTimerRef = useRef<number | null>(null);
  const lockedToastAtRef = useRef<number>(0);

  const notifyLocked = useCallback((): void => {
    const now = Date.now();
    if (now - lockedToastAtRef.current < 800) return;
    lockedToastAtRef.current = now;
    toast("This path is locked. Unlock it to edit nodes or connections.", {
      variant: "info",
    });
  }, [toast]);

  useEffect((): void | (() => void) => {
    if (!lastDrop) return;
    if (lastDropTimerRef.current) {
      window.clearTimeout(lastDropTimerRef.current);
    }
    lastDropTimerRef.current = window.setTimeout((): void => {
      setLastDrop(null);
      lastDropTimerRef.current = null;
    }, 1600);
    return (): void => {
      if (lastDropTimerRef.current) {
        window.clearTimeout(lastDropTimerRef.current);
        lastDropTimerRef.current = null;
      }
    };
  }, [lastDrop]);

  // Cleanup RAF on unmount
  useEffect((): () => void => {
    return (): void => {
      if (rafIdRef.current !== null) {
        cancelAnimationFrame(rafIdRef.current);
      }
    };
  }, []);

  useEffect((): void | (() => void) => {
    const handlePointerDown = (event: PointerEvent): void => {
      const target = event.target as HTMLElement | null;
      if (target?.closest("[data-port]")) return;
      if (target?.closest("path")) return;
      if (target?.closest("[data-edge-panel]")) return;
      setConnecting(null);
      setConnectingPos(null);
      setSelectedEdgeId(null);
    };
    window.addEventListener("pointerdown", handlePointerDown);
    return (): void => window.removeEventListener("pointerdown", handlePointerDown);
  }, []);

  useEffect((): void | (() => void) => {
    const handlePointerUp = (): void => {
      setConnecting(null);
      setConnectingPos(null);
    };
    window.addEventListener("pointerup", handlePointerUp);
    return (): void => window.removeEventListener("pointerup", handlePointerUp);
  }, []);

  const handleRemoveEdge = useCallback(
    (edgeId: string): void => {
      if (isPathLocked) {
        notifyLocked();
        return;
      }
      setEdges((prev: Edge[]): Edge[] => {
        const target = prev.find((edge: Edge): boolean => edge.id === edgeId) ?? null;
        if (!target) return prev;
        const remaining = prev.filter((edge: Edge): boolean => edge.id !== edgeId);
        clearRuntimeInputsForEdges([target], remaining);
        return remaining;
      });
      if (selectedEdgeId === edgeId) {
        setSelectedEdgeId(null);
      }
    },
    [clearRuntimeInputsForEdges, isPathLocked, notifyLocked, selectedEdgeId, setEdges]
  );

  const handleDisconnectPort = useCallback(
    (direction: "input" | "output", nodeId: string, port: string): void => {
      if (isPathLocked) {
        notifyLocked();
        return;
      }
      setEdges((prev: Edge[]): Edge[] => {
        const shouldRemove = (edge: Edge): boolean =>
          direction === "input"
            ? edge.to === nodeId && edge.toPort === port
            : edge.from === nodeId && edge.fromPort === port;
        const removed = prev.filter((edge: Edge): boolean => shouldRemove(edge));
        const remaining = prev.filter((edge: Edge): boolean => !shouldRemove(edge));
        if (selectedEdgeId) {
          const selectedEdge = prev.find((edge: Edge) => edge.id === selectedEdgeId);
          if (selectedEdge && shouldRemove(selectedEdge)) {
            setSelectedEdgeId(null);
          }
        }
        clearRuntimeInputsForEdges(removed, remaining);
        return remaining;
      });
    },
    [clearRuntimeInputsForEdges, isPathLocked, notifyLocked, selectedEdgeId, setEdges]
  );

  const isTypingTarget = (target: EventTarget | null): boolean => {
    const element = target as HTMLElement | null;
    if (!element) return false;
    if (element.isContentEditable) return true;
    const tag = element.tagName?.toLowerCase();
    if (tag === "input" || tag === "textarea" || tag === "select") return true;
    return Boolean(element.closest("input, textarea, select, [contenteditable=\"true\"]"));
  };

  const handleDeleteSelectedNode = useCallback((): void => {
    if (!selectedNodeId) return;
    if (isPathLocked) {
      notifyLocked();
      return;
    }
    const targetNode = nodes.find((node: AiNode): boolean => node.id === selectedNodeId);
    const label = targetNode?.title || "this node";
    const confirmed = window.confirm(`Remove ${label}? This will delete connected wires.`);
    if (!confirmed) return;
    setNodes((prev: AiNode[]): AiNode[] => prev.filter((node: AiNode): boolean => node.id !== selectedNodeId));
    setEdges((prev: Edge[]): Edge[] => {
      const removed = prev.filter(
        (edge: Edge): boolean => edge.from === selectedNodeId || edge.to === selectedNodeId
      );
      const remaining = prev.filter(
        (edge: Edge): boolean => edge.from !== selectedNodeId && edge.to !== selectedNodeId
      );
      clearRuntimeInputsForEdges(removed, remaining);
      return remaining;
    });
    setSelectedNodeId(null);
  }, [
    nodes,
    selectedNodeId,
    clearRuntimeInputsForEdges,
    isPathLocked,
    notifyLocked,
    setEdges,
    setNodes,
    setSelectedNodeId,
  ]);

  useEffect((): void | (() => void) => {
    const handleKeyDown = (event: KeyboardEvent): void => {
      if (event.key === "Escape") {
        setConnecting(null);
        setConnectingPos(null);
        setSelectedEdgeId(null);
      }
      if (event.key === "Backspace" || event.key === "Delete") {
        if (isTypingTarget(event.target)) return;
        if (selectedEdgeId) {
          event.preventDefault();
          handleRemoveEdge(selectedEdgeId);
          return;
        }
        if (selectedNodeId) {
          event.preventDefault();
          handleDeleteSelectedNode();
        }
      }
    };
    window.addEventListener("keydown", handleKeyDown);
    return (): void => window.removeEventListener("keydown", handleKeyDown);
  }, [selectedEdgeId, selectedNodeId, handleRemoveEdge, handleDeleteSelectedNode]);

  useEffect((): void => {
    setEdges((prev: Edge[]): Edge[] => sanitizeEdges(nodes, prev));
  }, [nodes, setEdges]);

  const setViewClamped = (next: { x: number; y: number; scale: number }): void => {
    const viewport = viewportRef.current?.getBoundingClientRect() ?? null;
    const clampedScale = clampScale(next.scale);
    const clamped = clampTranslate(next.x, next.y, clampedScale, viewport);
    setView({ x: clamped.x, y: clamped.y, scale: clampedScale });
  };

  const zoomTo = (targetScale: number): void => {
    const viewport = viewportRef.current?.getBoundingClientRect() ?? null;
    if (!viewport) {
      setViewClamped({ ...view, scale: targetScale });
      return;
    }
    const centerX = viewport.width / 2;
    const centerY = viewport.height / 2;
    const nextScale = clampScale(targetScale);
    const canvasX = (centerX - view.x) / view.scale;
    const canvasY = (centerY - view.y) / view.scale;
    const nextX = centerX - canvasX * nextScale;
    const nextY = centerY - canvasY * nextScale;
    const clamped = clampTranslate(nextX, nextY, nextScale, viewport);
    setView({ x: clamped.x, y: clamped.y, scale: nextScale });
  };

  const fitToNodesWith = (items: AiNode[]): void => {
    const viewport = viewportRef.current?.getBoundingClientRect() ?? null;
    if (!viewport || items.length === 0) {
      resetView();
      return;
    }
    const padding = 120;
    const bounds = items.reduce(
      (acc: { minX: number; minY: number; maxX: number; maxY: number }, node: AiNode) => {
        const x1 = node.position.x;
        const y1 = node.position.y;
        const x2 = node.position.x + NODE_WIDTH;
        const y2 = node.position.y + NODE_MIN_HEIGHT;
        return {
          minX: Math.min(acc.minX, x1),
          minY: Math.min(acc.minY, y1),
          maxX: Math.max(acc.maxX, x2),
          maxY: Math.max(acc.maxY, y2),
        };
      },
      {
        minX: Number.POSITIVE_INFINITY,
        minY: Number.POSITIVE_INFINITY,
        maxX: Number.NEGATIVE_INFINITY,
        maxY: Number.NEGATIVE_INFINITY,
      }
    );
    const width = Math.max(1, bounds.maxX - bounds.minX + padding * 2);
    const height = Math.max(1, bounds.maxY - bounds.minY + padding * 2);
    const scaleX = viewport.width / width;
    const scaleY = viewport.height / height;
    const nextScale = clampScale(Math.min(scaleX, scaleY));
    const centerX = bounds.minX + (bounds.maxX - bounds.minX) / 2;
    const centerY = bounds.minY + (bounds.maxY - bounds.minY) / 2;
    const nextX = viewport.width / 2 - centerX * nextScale;
    const nextY = viewport.height / 2 - centerY * nextScale;
    const clamped = clampTranslate(nextX, nextY, nextScale, viewport);
    setView({ x: clamped.x, y: clamped.y, scale: nextScale });
  };

  const fitToNodes = (): void => {
    fitToNodesWith(nodes);
  };

  const resetView = (): void => {
    setViewClamped({ x: VIEW_MARGIN, y: VIEW_MARGIN, scale: 1 });
  };

  const ensureNodeVisible = (node: AiNode): void => {
    const viewport = viewportRef.current?.getBoundingClientRect() ?? null;
    if (!viewport) return;
    const nodeLeft = node.position.x * view.scale + view.x;
    const nodeTop = node.position.y * view.scale + view.y;
    const nodeRight = nodeLeft + NODE_WIDTH * view.scale;
    const nodeBottom = nodeTop + NODE_MIN_HEIGHT * view.scale;
    let nextX = view.x;
    let nextY = view.y;
    if (nodeLeft < VIEW_MARGIN) {
      nextX += VIEW_MARGIN - nodeLeft;
    } else if (nodeRight > viewport.width - VIEW_MARGIN) {
      nextX -= nodeRight - (viewport.width - VIEW_MARGIN);
    }
    if (nodeTop < VIEW_MARGIN) {
      nextY += VIEW_MARGIN - nodeTop;
    } else if (nodeBottom > viewport.height - VIEW_MARGIN) {
      nextY -= nodeBottom - (viewport.height - VIEW_MARGIN);
    }
    const clamped = clampTranslate(nextX, nextY, view.scale, viewport);
    setView({ x: clamped.x, y: clamped.y, scale: view.scale });
  };

  const getPortPosition = useCallback((
    node: AiNode,
    portName: string | undefined,
    side: "input" | "output"
  ): { x: number; y: number } => {
    const ports = side === "input" ? node.inputs : node.outputs;
    const index = portName ? ports.indexOf(portName) : -1;
    const safeIndex = index >= 0 ? index : Math.max(0, Math.floor(ports.length / 2));
    const x = node.position.x + (side === "output" ? NODE_WIDTH : 0);
    const y = node.position.y + getPortOffsetY(safeIndex, ports.length);
    return { x, y };
  }, []);

  const handleReconnectInput = useCallback(
    (event: React.PointerEvent<HTMLButtonElement>, nodeId: string, port: string): void => {
      if (isPathLocked) {
        notifyLocked();
        return;
      }
      if (connecting) return;
      let edgeToMove: Edge | null = null;
      for (let index = edges.length - 1; index >= 0; index -= 1) {
        const edge = edges[index];
        if (edge && edge.to === nodeId && edge.toPort === port) {
          edgeToMove = edge;
          break;
        }
      }
      if (!edgeToMove || !edgeToMove.from || !edgeToMove.fromPort) return;
      const fromNode = nodes.find((node: AiNode): boolean => node.id === edgeToMove.from);
      if (!fromNode) return;
      const start = getPortPosition(fromNode, edgeToMove.fromPort, "output");
      const viewport = viewportRef.current?.getBoundingClientRect();
      const nextPos = viewport
        ? {
            x: (event.clientX - viewport.left - view.x) / view.scale,
            y: (event.clientY - viewport.top - view.y) / view.scale,
          }
        : start;
      setEdges((prev: Edge[]): Edge[] => {
        const remaining = prev.filter(
          (edge: Edge): boolean => edge.id !== edgeToMove.id
        );
        clearRuntimeInputsForEdges([edgeToMove], remaining);
        return remaining;
      });
      if (selectedEdgeId === edgeToMove.id) {
        setSelectedEdgeId(null);
      }
      setConnecting({ fromNodeId: edgeToMove.from, fromPort: edgeToMove.fromPort, start });
      setConnectingPos(nextPos);
    },
    [
      clearRuntimeInputsForEdges,
      connecting,
      edges,
      getPortPosition,
      isPathLocked,
      nodes,
      notifyLocked,
      selectedEdgeId,
      setEdges,
      view,
    ]
  );

  // Create a stable key based only on edge-relevant node data (position, ports)
  // This prevents edge recalculation when only config/title changes occur
  const nodePositionsKey = useMemo(
    (): string =>
      nodes
        .map(
          (n: AiNode): string =>
            `${n.id}:${n.position.x}:${n.position.y}:${n.inputs.length}:${n.outputs.length}`
        )
        .join("|"),
    [nodes]
  );

  const edgePaths = useMemo((): { id: string; path: string; label?: string | undefined; arrow?: { x: number; y: number; angle: number } | undefined }[] => {
    const nodeMap = new Map(nodes.map((node: AiNode): [string, AiNode] => [node.id, node]));
    const midpoint = (a: { x: number; y: number }, b: { x: number; y: number }): { x: number; y: number } => ({
      x: (a.x + b.x) / 2,
      y: (a.y + b.y) / 2,
    });
    return edges
      .map((edge: Edge): { id: string; path: string; label?: string | undefined; arrow?: { x: number; y: number; angle: number } | undefined } | null => {
        const from = nodeMap.get(edge.from);
        const to = nodeMap.get(edge.to);
        if (!from || !to) return null;
        const fromPort =
          edge.fromPort ?? (from.outputs.length > 0 ? from.outputs[0] : undefined);
        const toPort = edge.toPort ?? (to.inputs.length > 0 ? to.inputs[0] : undefined);
        const fromPos = getPortPosition(from, fromPort, "output");
        const toPos = getPortPosition(to, toPort, "input");
        const p0 = { x: fromPos.x, y: fromPos.y };
        const p3 = { x: toPos.x, y: toPos.y };
        const midX = p0.x + (p3.x - p0.x) * 0.5;
        const p1 = { x: midX, y: p0.y };
        const p2 = { x: midX, y: p3.y };
        const q0 = midpoint(p0, p1);
        const q1 = midpoint(p1, p2);
        const q2 = midpoint(p2, p3);
        const r0 = midpoint(q0, q1);
        const r1 = midpoint(q1, q2);
        const s = midpoint(r0, r1);
        const path = [
          `M ${p0.x} ${p0.y}`,
          `C ${q0.x} ${q0.y}, ${r0.x} ${r0.y}, ${s.x} ${s.y}`,
          `C ${r1.x} ${r1.y}, ${q2.x} ${q2.y}, ${p3.x} ${p3.y}`,
        ].join(" ");
        let dx = r1.x - r0.x;
        let dy = r1.y - r0.y;
        if (Math.abs(dx) < 0.001 && Math.abs(dy) < 0.001) {
          dx = p3.x - p0.x;
          dy = p3.y - p0.y;
        }
        const angle = (Math.atan2(dy, dx) * 180) / Math.PI;
        return {
          id: edge.id,
          path,
          label: edge.label,
          arrow: { x: s.x, y: s.y, angle },
        };
      })
      .filter(Boolean) as { id: string; path: string; label?: string | undefined; arrow?: { x: number; y: number; angle: number } | undefined }[];
  }, [edges, getPortPosition, nodePositionsKey, nodes]);

  const handlePointerDown = (
    event: React.PointerEvent<HTMLDivElement>,
    nodeId: string
  ): void => {
    if (isPathLocked) {
      notifyLocked();
      return;
    }
    event.stopPropagation();
    const target = event.currentTarget;
    target.setPointerCapture(event.pointerId);
    const viewport = viewportRef.current?.getBoundingClientRect();
    if (!viewport) return;
    const node = nodes.find((item: AiNode): boolean => item.id === nodeId);
    if (!node) return;
    const canvasX = (event.clientX - viewport.left - view.x) / view.scale;
    const canvasY = (event.clientY - viewport.top - view.y) / view.scale;
    setDragState({
      nodeId,
      offsetX: canvasX - node.position.x,
      offsetY: canvasY - node.position.y,
    });
  };

  const handlePointerMove = (
    event: React.PointerEvent<HTMLDivElement>,
    nodeId: string
  ): void => {
    if (!dragState || dragState.nodeId !== nodeId) return;
    const viewport = viewportRef.current?.getBoundingClientRect();
    if (!viewport) return;
    const nextX = Math.min(
      Math.max((event.clientX - viewport.left - view.x) / view.scale - dragState.offsetX, 16),
      CANVAS_WIDTH - NODE_WIDTH - 16
    );
    const nextY = Math.min(
      Math.max((event.clientY - viewport.top - view.y) / view.scale - dragState.offsetY, 16),
      CANVAS_HEIGHT - NODE_MIN_HEIGHT - 16
    );

    // RAF throttling: batch position updates to animation frames
    pendingDragRef.current = { nodeId, x: nextX, y: nextY };
    if (rafIdRef.current === null) {
      rafIdRef.current = requestAnimationFrame((): void => {
        if (pendingDragRef.current) {
          const { nodeId: id, x, y } = pendingDragRef.current;
          setNodes((prev: AiNode[]): AiNode[] =>
            prev.map((node: AiNode): AiNode =>
              node.id === id ? { ...node, position: { x, y } } : node
            )
          );
        }
        rafIdRef.current = null;
      });
    }
  };

  const handlePointerUp = (
    event: React.PointerEvent<HTMLDivElement>,
    nodeId: string
  ): void => {
    if (dragState?.nodeId !== nodeId) return;
    event.currentTarget.releasePointerCapture(event.pointerId);

    // Flush any pending RAF drag update immediately on pointer up
    if (rafIdRef.current !== null) {
      cancelAnimationFrame(rafIdRef.current);
      rafIdRef.current = null;
    }
    if (pendingDragRef.current) {
      const { nodeId: id, x, y } = pendingDragRef.current;
      setNodes((prev: AiNode[]): AiNode[] =>
        prev.map((node: AiNode): AiNode =>
          node.id === id ? { ...node, position: { x, y } } : node
        )
      );
      pendingDragRef.current = null;
    }

    setDragState(null);
  };

  const handleDragStart = (
    event: React.DragEvent<HTMLDivElement>,
    node: NodeDefinition
  ): void => {
    if (isPathLocked) {
      event.preventDefault();
      notifyLocked();
      return;
    }
    const payload = JSON.stringify(node);
    setDragData(
      event.dataTransfer,
      { [DRAG_KEYS.AI_NODE]: payload },
      { text: payload, effectAllowed: "copy" }
    );
  };

  const handleDrop = (event: React.DragEvent<HTMLDivElement>): void => {
    event.preventDefault();
    event.stopPropagation();
    if (isPathLocked) {
      notifyLocked();
      return;
    }
    const viewport = viewportRef.current?.getBoundingClientRect();
    if (!viewport) return;
    const canvasRect = canvasRef.current?.getBoundingClientRect() ?? null;
    const types = Array.from(event.dataTransfer.types ?? []);
    const nodeData = getFirstDragValue(event.dataTransfer, [DRAG_KEYS.AI_NODE]);
    const textData = getFirstDragValue(event.dataTransfer, [DRAG_KEYS.TEXT]);
    const raw = nodeData || textData;
    if (!raw) return;
    if (!nodeData) {
      const trimmed = raw.trim();
      if (!trimmed || (trimmed[0] !== "{" && trimmed[0] !== "[")) {
        return;
      }
      if (!types.includes(DRAG_KEYS.TEXT)) {
        return;
      }
    }
    let payload: NodeDefinition | null = null;
    try {
      payload = JSON.parse(raw) as NodeDefinition;
    } catch (error) {
      reportAiPathsError(
        error,
        { action: "dropNode", dataPreview: raw.slice(0, 120) },
        "Invalid node payload dropped:"
      );
      toast("Failed to add node. Drag again.", { variant: "error" });
      return;
    }
    if (!payload || typeof payload.type !== "string" || !Array.isArray(payload.inputs) || !Array.isArray(payload.outputs)) {
      return;
    }
    const localX = canvasRect
      ? (event.clientX - canvasRect.left) / view.scale
      : (event.clientX - viewport.left - view.x) / view.scale;
    const localY = canvasRect
      ? (event.clientY - canvasRect.top) / view.scale
      : (event.clientY - viewport.top - view.y) / view.scale;
    const nextX = Math.min(
      Math.max(localX - NODE_WIDTH / 2, 16),
      CANVAS_WIDTH - NODE_WIDTH - 16
    );
    const nextY = Math.min(
      Math.max(localY - NODE_MIN_HEIGHT / 2, 16),
      CANVAS_HEIGHT - NODE_MIN_HEIGHT - 16
    );
    const defaultConfig = getDefaultConfigForType(payload.type, payload.outputs, payload.inputs);
    const mergedConfig = payload.config
      ? {
          ...(defaultConfig ?? {}),
          ...payload.config,
        }
      : defaultConfig;
    const newNode: AiNode = {
      ...payload,
      id: `node-${Math.random().toString(36).slice(2, 8)}`,
      position: { x: nextX, y: nextY },
      ...(mergedConfig ? { config: mergedConfig } : {}),
    };
    setSelectedNodeId(newNode.id);
    setNodes((prev: AiNode[]): AiNode[] => [...prev, newNode]);
    ensureNodeVisible(newNode);
    setLastDrop({ x: nextX, y: nextY });
    toast(`Node added: ${payload.title}`, { variant: "success" });
  };

  const handleDragOver = (event: React.DragEvent<HTMLDivElement>): void => {
    event.preventDefault();
    event.dataTransfer.dropEffect = "copy";
  };

  const handleStartConnection = (
    event: React.PointerEvent<HTMLButtonElement>,
    node: AiNode,
    port: string
  ): void => {
    if (isPathLocked) {
      notifyLocked();
      return;
    }
    event.stopPropagation();
    const start = getPortPosition(node, port, "output");
    setConnecting({ fromNodeId: node.id, fromPort: port, start });
    setConnectingPos(start);
  };

  const handleCompleteConnection = (
    event: React.PointerEvent<HTMLButtonElement>,
    node: AiNode,
    port: string
  ): void => {
    if (isPathLocked) {
      notifyLocked();
      return;
    }
    event.stopPropagation();
    if (!connecting) return;
    if (connecting.fromNodeId === node.id && connecting.fromPort === port) {
      setConnecting(null);
      setConnectingPos(null);
      return;
    }

    const fromNode = nodes.find((n: AiNode): boolean => n.id === connecting.fromNodeId);
    if (!fromNode) {
      setConnecting(null);
      setConnectingPos(null);
      return;
    }

    const validation = validateConnection(
      fromNode,
      node,
      connecting.fromPort,
      port
    );

    if (!validation.valid) {
      toast(validation.message ?? "Invalid connection.", { variant: "error" });
      setConnecting(null);
      setConnectingPos(null);
      return;
    }

    setEdges((prev: Edge[]): Edge[] => [
      ...prev,
      {
        id: `edge-${Math.random().toString(36).slice(2, 8)}`,
        from: connecting.fromNodeId,
        to: node.id,
        fromPort: connecting.fromPort,
        toPort: port,
      },
    ]);
    toast("Connection created.", { variant: "success" });
    setConnecting(null);
    setConnectingPos(null);
  };

  const handlePanStart = (event: React.PointerEvent<HTMLDivElement>): void => {
    const canvasEl = canvasRef.current;
    const targetEl = event.target as Element | null;
    if (targetEl?.closest("path")) return;
    if (
      event.target !== event.currentTarget &&
      event.target !== canvasEl &&
      targetEl?.tagName?.toLowerCase() !== "svg"
    ) {
      return;
    }
    if (connecting) {
      setConnecting(null);
      setConnectingPos(null);
      return;
    }
    const target = event.currentTarget;
    target.setPointerCapture(event.pointerId);
    setPanState({
      startX: event.clientX,
      startY: event.clientY,
      originX: view.x,
      originY: view.y,
    });
  };

  const handlePanMove = (event: React.PointerEvent<HTMLDivElement>): void => {
    if (connecting) {
      const viewport = viewportRef.current?.getBoundingClientRect();
      if (!viewport) return;
      const x = (event.clientX - viewport.left - view.x) / view.scale;
      const y = (event.clientY - viewport.top - view.y) / view.scale;
      setConnectingPos({ x, y });
      return;
    }
    if (!panState) return;
    const viewport = viewportRef.current?.getBoundingClientRect() ?? null;
    const nextX = panState.originX + (event.clientX - panState.startX);
    const nextY = panState.originY + (event.clientY - panState.startY);
    const clamped = clampTranslate(nextX, nextY, view.scale, viewport);
    setView({ x: clamped.x, y: clamped.y, scale: view.scale });
  };

  const handlePanEnd = (event: React.PointerEvent<HTMLDivElement>): void => {
    if (panState) {
      event.currentTarget.releasePointerCapture(event.pointerId);
      setPanState(null);
    }
    if (connecting) {
      setConnecting(null);
      setConnectingPos(null);
    }
  };

  const handleSelectEdge = (edgeId: string | null): void => {
    setSelectedEdgeId(edgeId);
    if (edgeId) {
      setSelectedNodeId(null);
    }
  };

  const handleSelectNode = (nodeId: string): void => {
    setSelectedEdgeId(null);
    setSelectedNodeId(nodeId);
  };

  const getCanvasCenterPosition = (): { x: number; y: number } => {
    const viewport = viewportRef.current?.getBoundingClientRect() ?? null;
    if (!viewport) return { x: VIEW_MARGIN, y: VIEW_MARGIN };
    const centerX = (viewport.width / 2 - view.x) / view.scale;
    const centerY = (viewport.height / 2 - view.y) / view.scale;
    const nextX = Math.min(
      Math.max(centerX - NODE_WIDTH / 2, 16),
      CANVAS_WIDTH - NODE_WIDTH - 16
    );
    const nextY = Math.min(
      Math.max(centerY - NODE_MIN_HEIGHT / 2, 16),
      CANVAS_HEIGHT - NODE_MIN_HEIGHT - 16
    );
    return { x: nextX, y: nextY };
  };

  const connectingFromNode = useMemo(
    (): AiNode | null => (connecting ? nodes.find((node: AiNode): boolean => node.id === connecting.fromNodeId) ?? null : null),
    [connecting, nodes]
  );

  return {
    viewportRef,
    canvasRef,
    view,
    panState,
    dragState,
    connecting,
    connectingPos,
    lastDrop,
    selectedEdgeId,
    edgePaths,
    connectingFromNode,
    ensureNodeVisible,
    getCanvasCenterPosition,
    handlePointerDown,
    handlePointerMove,
    handlePointerUp,
    handleDragStart,
    handleDrop,
    handleDragOver,
    handleStartConnection,
    handleCompleteConnection,
    handlePanStart,
    handlePanMove,
    handlePanEnd,
    handleReconnectInput,
    handleRemoveEdge,
    handleDisconnectPort,
    handleDeleteSelectedNode,
    handleSelectEdge,
    handleSelectNode,
    zoomTo,
    fitToNodes,
    resetView,
  };
}

import "server-only";

import type { NextRequest } from "next/server";
import { randomUUID } from "crypto";
import { getMongoDb } from "@/shared/lib/db/mongo-client";
import prisma from "@/shared/lib/db/prisma";
import type { CmsRepository } from "@/features/cms/types/services/cms-repository";
import type { CmsDomain, Slug } from "@/features/cms/types";
import { getCmsDataProvider } from "@/features/cms/services/cms-provider";
import { getCmsDomainSettings } from "@/features/cms/services/cms-domain-settings";

type CmsDomainRecord = {
  id: string;
  domain: string;
  aliasOf?: string | null;
  createdAt: Date;
  updatedAt: Date;
};

export type CmsDomainResponse = {
  id: string;
  domain: string;
  aliasOf?: string | null;
  createdAt?: string;
  updatedAt?: string;
};

type CmsDomainSlugLink = {
  domainId: string;
  slugId: string;
  isDefault?: boolean;
  assignedAt: Date;
  updatedAt?: Date;
};

const DOMAIN_COLLECTION = "cms_domains";
const DOMAIN_SLUGS_COLLECTION = "cms_domain_slugs";
const SLUGS_COLLECTION = "cms_slugs";

type SlugDocument = {
  id: string;
  isDefault?: boolean;
  updatedAt?: Date;
};

const getFallbackDomain = (): string => {
  const url =
    process.env.NEXT_PUBLIC_APP_URL ||
    process.env.NEXTAUTH_URL ||
    "http://localhost";
  try {
    return new URL(url).hostname.toLowerCase();
  } catch {
    return "default";
  }
};

const buildDefaultDomain = (hostHeader: string | null): CmsDomain => ({
  id: "default-domain",
  domain: normalizeHost(hostHeader),
  createdAt: new Date().toISOString(),
  updatedAt: new Date().toISOString(),
});

const normalizeHost = (hostHeader: string | null): string => {
  if (!hostHeader) return getFallbackDomain();
  const raw = hostHeader.split(",")[0]?.trim() ?? "";
  if (!raw) return getFallbackDomain();
  try {
    return new URL(`http://${raw}`).hostname.toLowerCase();
  } catch {
    return raw.toLowerCase();
  }
};

const getHostFromRequest = (req: NextRequest): string | null =>
  req.headers.get("x-forwarded-host") ?? req.headers.get("host");

const getHostFromHeaders = (
  headers: Headers | { get?: (key: string) => string | null } | Record<string, unknown> | null | undefined
): string | null => {
  if (!headers) return null;
  if (typeof (headers as Headers).get === "function") {
    return (headers as Headers).get("x-forwarded-host") ?? (headers as Headers).get("host");
  }
  if (typeof headers === "function") {
    try {
      // Handle accidental passing of the headers() function itself.
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      return getHostFromHeaders((headers as any)());
    } catch {
      return null;
    }
  }
  if (typeof headers === "object") {
    const record = headers as Record<string, unknown>;
    const forwarded =
      record["x-forwarded-host"] ??
      record["X-Forwarded-Host"] ??
      record["host"] ??
      record["Host"];
    if (typeof forwarded === "string") return forwarded;
  }
  return null;
};

const canUsePrismaSlugs = (): boolean =>
  Boolean(process.env.DATABASE_URL) && "slug" in prisma;

export async function isDomainZoningEnabled(): Promise<boolean> {
  if (!process.env.MONGODB_URI) return false;
  const settings = await getCmsDomainSettings();
  return settings.zoningEnabled;
}

export async function setGlobalDefaultSlug(slugId: string | null): Promise<void> {
  const provider = await getCmsDataProvider();
  if (provider === "mongodb") {
    if (!process.env.MONGODB_URI) return;
    const db = await getMongoDb();
    const now = new Date();
    await db.collection<SlugDocument>(SLUGS_COLLECTION).updateMany(
      {},
      { $set: { isDefault: false, updatedAt: now } }
    );
    if (!slugId) return;
    await db.collection<SlugDocument>(SLUGS_COLLECTION).updateOne(
      { id: slugId },
      { $set: { isDefault: true, updatedAt: now } }
    );
    return;
  }
  if (!canUsePrismaSlugs()) return;
  await prisma.slug.updateMany({ data: { isDefault: false } });
  if (!slugId) return;
  try {
    await prisma.slug.update({ where: { id: slugId }, data: { isDefault: true } });
  } catch {
    // Ignore missing slug
  }
}

export async function resolveCmsDomainFromRequest(req: NextRequest): Promise<CmsDomain> {
  const host = getHostFromRequest(req);
  return resolveCmsDomainByHost(host);
}

export async function resolveCmsDomainFromHeaders(headers: Headers | { get?: (key: string) => string | null } | null | undefined): Promise<CmsDomain> {
  const host = getHostFromHeaders(headers);
  return resolveCmsDomainByHost(host);
}

const getDomainRecordById = async (domainId: string): Promise<CmsDomainRecord | null> => {
  if (!process.env.MONGODB_URI) return null;
  const db = await getMongoDb();
  return db
    .collection<CmsDomainRecord>(DOMAIN_COLLECTION)
    .findOne({ id: domainId });
};

export async function resolveCmsDomainScopeById(domainId: string): Promise<CmsDomain | null> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) {
    return buildDefaultDomain(null);
  }
  let current = await getDomainRecordById(domainId);
  if (!current) return null;
  const visited = new Set<string>([current.id]);
  while (current.aliasOf) {
    if (visited.has(current.aliasOf)) break;
    const next = await getDomainRecordById(current.aliasOf);
    if (!next) break;
    visited.add(next.id);
    current = next;
  }
  return toDomainResponse(current);
}

export async function resolveCmsDomainByHost(hostHeader: string | null): Promise<CmsDomain> {
  const domain = normalizeHost(hostHeader);
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) {
    return buildDefaultDomain(hostHeader);
  }

  const db = await getMongoDb();
  const existing = await db
    .collection<CmsDomainRecord>(DOMAIN_COLLECTION)
    .findOne({ domain });
  if (existing) {
    const scoped = await resolveCmsDomainScopeById(existing.id);
    return scoped ?? toDomainResponse(existing);
  }

  const now = new Date();
  const doc: CmsDomainRecord = {
    id: randomUUID(),
    domain,
    aliasOf: null,
    createdAt: now,
    updatedAt: now,
  };
  await db.collection<CmsDomainRecord>(DOMAIN_COLLECTION).insertOne(doc);
  return toDomainResponse(doc);
}

export async function getCmsDomainById(domainId: string): Promise<CmsDomain | null> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) {
    return buildDefaultDomain(null);
  }
  const doc = await getDomainRecordById(domainId);
  return doc ? toDomainResponse(doc) : null;
}

export async function getDomainSlugLinks(domainId: string): Promise<CmsDomainSlugLink[]> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) return [];
  const db = await getMongoDb();
  return db
    .collection<CmsDomainSlugLink>(DOMAIN_SLUGS_COLLECTION)
    .find({ domainId })
    .toArray();
}

export async function getDomainIdsForSlug(slugId: string): Promise<string[]> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) return [];
  const db = await getMongoDb();
  const links = await db
    .collection<CmsDomainSlugLink>(DOMAIN_SLUGS_COLLECTION)
    .find({ slugId })
    .toArray();
  const ids = links.map((link: CmsDomainSlugLink) => link.domainId);
  return Array.from(new Set(ids));
}

const toDomainResponse = (doc: CmsDomainRecord): CmsDomainResponse => ({
  id: doc.id,
  domain: doc.domain,
  aliasOf: doc.aliasOf ?? null,
  createdAt: doc.createdAt?.toISOString?.() ?? undefined,
  updatedAt: doc.updatedAt?.toISOString?.() ?? undefined,
});

export async function listCmsDomains(): Promise<CmsDomainResponse[]> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) return [];
  const db = await getMongoDb();
  const docs = await db
    .collection<CmsDomainRecord>(DOMAIN_COLLECTION)
    .find()
    .sort({ domain: 1 })
    .toArray();
  return docs.map((doc: CmsDomainRecord) => toDomainResponse(doc));
}

export async function createCmsDomain(domain: string): Promise<CmsDomainResponse> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) {
    return { id: "default-domain", domain: normalizeHost(domain) };
  }
  const db = await getMongoDb();
  const normalized = normalizeHost(domain);
  const existing = await db
    .collection<CmsDomainRecord>(DOMAIN_COLLECTION)
    .findOne({ domain: normalized });
  if (existing) return toDomainResponse(existing);
  const now = new Date();
  const doc: CmsDomainRecord = {
    id: randomUUID(),
    domain: normalized,
    aliasOf: null,
    createdAt: now,
    updatedAt: now,
  };
  await db.collection<CmsDomainRecord>(DOMAIN_COLLECTION).insertOne(doc);
  return toDomainResponse(doc);
}

export async function deleteCmsDomain(domainId: string): Promise<void> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) return;
  const db = await getMongoDb();
  await db
    .collection<CmsDomainRecord>(DOMAIN_COLLECTION)
    .updateMany(
      { aliasOf: domainId },
      { $set: { aliasOf: null, updatedAt: new Date() } }
    );
  await db.collection<CmsDomainRecord>(DOMAIN_COLLECTION).deleteOne({ id: domainId });
  await db.collection<CmsDomainSlugLink>(DOMAIN_SLUGS_COLLECTION).deleteMany({ domainId });
}

export async function setCmsDomainAlias(domainId: string, aliasOf: string | null): Promise<CmsDomainResponse | null> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) return null;
  if (aliasOf === domainId) aliasOf = null;
  const db = await getMongoDb();
  const domain = await getDomainRecordById(domainId);
  if (!domain) return null;

  let targetId: string | null = aliasOf;
  if (aliasOf) {
    const canonical = await resolveCmsDomainScopeById(aliasOf);
    targetId = canonical?.id ?? null;
  }

  // Keep existing links so removing the alias restores the previous slug set.

  const updatedAt = new Date();
  await db
    .collection<CmsDomainRecord>(DOMAIN_COLLECTION)
    .updateOne(
      { id: domainId },
      { $set: { aliasOf: targetId ?? null, updatedAt } }
    );
  return toDomainResponse({
    ...domain,
    aliasOf: targetId ?? null,
    updatedAt,
  });
}

export async function isSlugAssignedToDomain(domainId: string, slugId: string): Promise<boolean> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) return true;
  const db = await getMongoDb();
  const doc = await db
    .collection<CmsDomainSlugLink>(DOMAIN_SLUGS_COLLECTION)
    .findOne({ domainId, slugId });
  return Boolean(doc);
}

export async function ensureDomainSlug(domainId: string, slugId: string): Promise<void> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) return;
  const db = await getMongoDb();
  await db.collection<CmsDomainSlugLink>(DOMAIN_SLUGS_COLLECTION).updateOne(
    { domainId, slugId },
    {
      $setOnInsert: {
        domainId,
        slugId,
        isDefault: false,
        assignedAt: new Date(),
      },
      $set: { updatedAt: new Date() },
    },
    { upsert: true }
  );
}

export async function removeDomainSlug(domainId: string, slugId: string): Promise<void> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) return;
  const db = await getMongoDb();
  await db.collection<CmsDomainSlugLink>(DOMAIN_SLUGS_COLLECTION).deleteOne({ domainId, slugId });
}

export async function setDomainDefaultSlug(domainId: string, slugId: string | null): Promise<void> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) return;
  const db = await getMongoDb();
  await db.collection<CmsDomainSlugLink>(DOMAIN_SLUGS_COLLECTION).updateMany(
    { domainId },
    { $set: { isDefault: false, updatedAt: new Date() } }
  );
  if (!slugId) return;
  await db.collection<CmsDomainSlugLink>(DOMAIN_SLUGS_COLLECTION).updateOne(
    { domainId, slugId },
    {
      $set: { isDefault: true, updatedAt: new Date() },
      $setOnInsert: { domainId, slugId, assignedAt: new Date() },
    },
    { upsert: true }
  );
}

export async function isSlugLinkedToAnyDomain(slugId: string): Promise<boolean> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) return false;
  const db = await getMongoDb();
  const count = await db
    .collection<CmsDomainSlugLink>(DOMAIN_SLUGS_COLLECTION)
    .countDocuments({ slugId }, { limit: 1 });
  return count > 0;
}

export async function getSlugsForDomain(domainId: string, repo: CmsRepository): Promise<Slug[]> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) {
    return repo.getSlugs();
  }
  const links = await getDomainSlugLinks(domainId);
  if (!links.length) return [];
  const map = new Map(links.map((link: CmsDomainSlugLink) => [link.slugId, link]));
  const slugs = await repo.getSlugs();
  return slugs
    .filter((slug: Slug) => map.has(slug.id))
    .map((slug: Slug) => ({
      ...slug,
      isDefault: map.get(slug.id)?.isDefault ?? false,
    }));
}

export async function getSlugForDomainById(
  domainId: string,
  slugId: string,
  repo: CmsRepository
): Promise<Slug | null> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) {
    return repo.getSlugById(slugId);
  }
  const slug = await repo.getSlugById(slugId);
  if (!slug) return null;
  const links = await getDomainSlugLinks(domainId);
  const link = links.find((item: CmsDomainSlugLink) => item.slugId === slugId);
  if (!link && process.env.MONGODB_URI) return null;
  return {
    ...slug,
    isDefault: link?.isDefault ?? false,
  };
}

export async function getSlugForDomainByValue(
  domainId: string,
  slugValue: string,
  repo: CmsRepository
): Promise<Slug | null> {
  const zoningEnabled = await isDomainZoningEnabled();
  if (!zoningEnabled) {
    return repo.getSlugByValue(slugValue);
  }
  const slug = await repo.getSlugByValue(slugValue);
  if (!slug) return null;
  const isAllowed = await isSlugAssignedToDomain(domainId, slug.id);
  if (!isAllowed) return null;
  const links = await getDomainSlugLinks(domainId);
  const link = links.find((item: CmsDomainSlugLink) => item.slugId === slug.id);
  return {
    ...slug,
    isDefault: link?.isDefault ?? false,
  };
}








import "server-only";

import { ObjectId } from "mongodb";
import { Prisma } from "@prisma/client";
import prisma from "@/shared/lib/db/prisma";
import { getMongoDb } from "@/shared/lib/db/mongo-client";
import { createFullDatabaseBackup } from "@/features/database/services/database-backup";
import { operationFailedError } from "@/shared/errors/app-error";

export type DatabaseSyncDirection = "mongo_to_prisma" | "prisma_to_mongo";

export type DatabaseSyncCollectionResult = {
  name: string;
  status: "completed" | "skipped" | "failed";
  sourceCount: number;
  targetDeleted: number;
  targetInserted: number;
  warnings?: string[];
  error?: string;
};

export type DatabaseSyncResult = {
  direction: DatabaseSyncDirection;
  startedAt: string;
  finishedAt: string;
  backups: Awaited<ReturnType<typeof createFullDatabaseBackup>>;
  collections: DatabaseSyncCollectionResult[];
};

const currencyCodes = new Set(["USD", "EUR", "PLN", "GBP", "SEK"]);
const countryCodes = new Set(["PL", "DE", "GB", "US", "SE"]);

const isObjectIdString = (value: string): boolean =>
  /^[a-fA-F0-9]{24}$/.test(value);

const toObjectIdMaybe = (value: string): ObjectId | string =>
  isObjectIdString(value) ? new ObjectId(value) : value;

const toDate = (value: unknown): Date | null => {
  if (!value) return null;
  if (value instanceof Date) return value;
  if (typeof value === "string" || typeof value === "number") {
    const parsed = new Date(value);
    return Number.isNaN(parsed.valueOf()) ? null : parsed;
  }
  return null;
};

const toJsonValue = (value: unknown): Prisma.JsonValue => {
  if (value === undefined || value === null) return null;
  if (value instanceof Date) return value.toISOString();
  if (value instanceof ObjectId) return value.toString();
  if (Array.isArray(value)) {
    return value.map((entry: unknown) => toJsonValue(entry)) as Prisma.JsonValue;
  }
  if (typeof value === "object") {
    const record = value as Record<string, unknown>;
    const entries = Object.entries(record).map(([key, entry]) => [
      key,
      toJsonValue(entry),
    ]);
    return Object.fromEntries(entries) as Prisma.JsonValue;
  }
  return value as Prisma.JsonValue;
};

const normalizeId = (doc: Record<string, unknown>): string => {
  const direct = doc.id;
  if (typeof direct === "string" && direct.trim()) return direct;
  const raw = doc._id;
  if (typeof raw === "string") return raw;
  if (raw && typeof raw === "object" && "toString" in raw) {
    return (raw as { toString: () => string }).toString();
  }
  return "";
};

const recordResult = (
  results: DatabaseSyncCollectionResult[],
  result: DatabaseSyncCollectionResult
): void => {
  results.push(result);
};

const listMongoCollections = async (): Promise<string[]> => {
  const mongo = await getMongoDb();
  const collections = await mongo.listCollections().toArray();
  return collections.map((entry: { name: string }) => entry.name);
};

const requireDatabases = (): void => {
  if (!process.env.MONGODB_URI) {
    throw operationFailedError("MongoDB is not configured.");
  }
  if (!process.env.DATABASE_URL) {
    throw operationFailedError("Prisma database is not configured.");
  }
};

export async function runDatabaseSync(direction: DatabaseSyncDirection): Promise<DatabaseSyncResult> {
  requireDatabases();
  const startedAt = new Date();
  const backups = await createFullDatabaseBackup();
  const collections: DatabaseSyncCollectionResult[] = [];

  if (direction === "mongo_to_prisma") {
    await syncMongoToPrisma(collections);
  } else {
    await syncPrismaToMongo(collections);
  }

  return {
    direction,
    startedAt: startedAt.toISOString(),
    finishedAt: new Date().toISOString(),
    backups,
    collections,
  };
}

async function syncMongoToPrisma(results: DatabaseSyncCollectionResult[]): Promise<void> {
  const mongo = await getMongoDb();

  const handledCollections = new Set<string>();
  const noteWarnings: string[] = [];

  const syncCollection = async (
    name: string,
    handler: () => Promise<{ sourceCount: number; targetDeleted: number; targetInserted: number; warnings?: string[] }>
  ): Promise<void> => {
    try {
      const { sourceCount, targetDeleted, targetInserted, warnings } = await handler();
      recordResult(results, {
        name,
        status: "completed",
        sourceCount,
        targetDeleted,
        targetInserted,
        ...(warnings?.length ? { warnings } : null),
      });
    } catch (error) {
      recordResult(results, {
        name,
        status: "failed",
        sourceCount: 0,
        targetDeleted: 0,
        targetInserted: 0,
        error: error instanceof Error ? error.message : "Sync failed.",
      });
      throw error;
    }
  };

  await syncCollection("settings", async () => {
    handledCollections.add("settings");
    const docs = await mongo.collection("settings").find({}).toArray();
    const byKey = new Map<string, { key: string; value: string; createdAt: Date; updatedAt: Date }>();
    docs.forEach((doc: Record<string, unknown>) => {
      const key =
        (doc as { key?: string }).key ??
        (doc as unknown as { _id?: ObjectId | string })._id?.toString() ??
        "";
      if (!key) return;
      const value = (doc as { value?: string }).value;
      const entry = {
        key,
        value: typeof value === "string" ? value : JSON.stringify(value ?? ""),
        createdAt: toDate((doc as { createdAt?: Date | string }).createdAt) ?? new Date(),
        updatedAt: toDate((doc as { updatedAt?: Date | string }).updatedAt) ?? new Date(),
      };
      const existing = byKey.get(key);
      if (!existing || entry.updatedAt > existing.updatedAt) {
        byKey.set(key, entry);
      }
    });
    const data = Array.from(byKey.values());
    const deleted = await prisma.setting.deleteMany();
    const created = data.length ? await prisma.setting.createMany({ data, skipDuplicates: true }) : { count: 0 };
    return { sourceCount: data.length, targetDeleted: deleted.count, targetInserted: created.count };
  });

  await syncCollection("users", async () => {
    handledCollections.add("users");
    const docs = await mongo.collection("users").find({}).toArray();
    const data = docs
      .map((doc: Record<string, unknown>) => {
        const id = normalizeId(doc as Record<string, unknown>);
        if (!id) return null;
        return {
          id,
          name: (doc as { name?: string | null }).name ?? null,
          email: (doc as { email?: string | null }).email ?? null,
          emailVerified: toDate((doc as { emailVerified?: Date | string | null }).emailVerified) ?? null,
          image: (doc as { image?: string | null }).image ?? null,
          passwordHash: (doc as { passwordHash?: string | null }).passwordHash ?? null,
        };
      })
      .filter(Boolean) as any;
    const deleted = await prisma.user.deleteMany();
    const created = data.length ? await prisma.user.createMany({ data }) : { count: 0 };
    return { sourceCount: data.length, targetDeleted: deleted.count, targetInserted: created.count };
  });

  await syncCollection("accounts", async () => {
    handledCollections.add("accounts");
    const docs = await mongo.collection("accounts").find({}).toArray();
    const data = docs
      .map((doc: Record<string, unknown>) => {
        const id = normalizeId(doc as Record<string, unknown>);
        const userIdRaw = (doc as { userId?: string | ObjectId }).userId;
        const userId = userIdRaw instanceof ObjectId ? userIdRaw.toString() : String(userIdRaw ?? "");
        if (!id || !userId) return null;
        return {
          id,
          userId,
          type: (doc as { type?: string }).type ?? "oauth",
          provider: (doc as { provider?: string }).provider ?? "",
          providerAccountId: (doc as { providerAccountId?: string }).providerAccountId ?? "",
          refresh_token: (doc as { refresh_token?: string | null }).refresh_token ?? null,
          access_token: (doc as { access_token?: string | null }).access_token ?? null,
          expires_at: (doc as { expires_at?: number | null }).expires_at ?? null,
          token_type: (doc as { token_type?: string | null }).token_type ?? null,
          scope: (doc as { scope?: string | null }).scope ?? null,
          id_token: (doc as { id_token?: string | null }).id_token ?? null,
          session_state: (doc as { session_state?: string | null }).session_state ?? null,
        };
      })
      .filter(Boolean) as any;
    const deleted = await prisma.account.deleteMany();
    const created = data.length ? await prisma.account.createMany({ data }) : { count: 0 };
    return { sourceCount: data.length, targetDeleted: deleted.count, targetInserted: created.count };
  });

  await syncCollection("sessions", async () => {
    handledCollections.add("sessions");
    const docs = await mongo.collection("sessions").find({}).toArray();
    const data = docs
      .map((doc: Record<string, unknown>) => {
        const id = normalizeId(doc as Record<string, unknown>);
        const userIdRaw = (doc as { userId?: string | ObjectId }).userId;
        const userId = userIdRaw instanceof ObjectId ? userIdRaw.toString() : String(userIdRaw ?? "");
        const sessionToken = (doc as { sessionToken?: string }).sessionToken;
        const expires = toDate((doc as { expires?: Date | string }).expires);
        if (!id || !userId || !sessionToken || !expires) return null;
        return {
          id,
          sessionToken,
          userId,
          expires,
        };
      })
      .filter(Boolean) as any;
    const deleted = await prisma.session.deleteMany();
    const created = data.length ? await prisma.session.createMany({ data }) : { count: 0 };
    return { sourceCount: data.length, targetDeleted: deleted.count, targetInserted: created.count };
  });

  await syncCollection("verification_tokens", async () => {
    handledCollections.add("verification_tokens");
    const docs = await mongo.collection("verification_tokens").find({}).toArray();
    const data = docs
      .map((doc: Record<string, unknown>) => {
        const identifier = (doc as { identifier?: string }).identifier;
        const token = (doc as { token?: string }).token;
        const expires = toDate((doc as { expires?: Date | string }).expires);
        if (!identifier || !token || !expires) return null;
        return { identifier, token, expires };
      })
      .filter(Boolean) as any;
    const deleted = await prisma.verificationToken.deleteMany();
    const created = data.length ? await prisma.verificationToken.createMany({ data }) : { count: 0 };
    return { sourceCount: data.length, targetDeleted: deleted.count, targetInserted: created.count };
  });

  await syncCollection("auth_security_profiles", async () => {
    handledCollections.add("auth_security_profiles");
    const docs = await mongo.collection("auth_security_profiles").find({}).toArray();
    const data = docs
      .map((doc: Record<string, unknown>) => {
        const id = normalizeId(doc as Record<string, unknown>);
        const userId = (doc as { userId?: string }).userId ?? id;
        if (!userId) return null;
        return {
          id,
          userId,
          mfaEnabled: Boolean((doc as { mfaEnabled?: boolean }).mfaEnabled),
          mfaSecret: (doc as { mfaSecret?: string | null }).mfaSecret ?? null,
          recoveryCodes: (doc as { recoveryCodes?: string[] }).recoveryCodes ?? [],
          allowedIps: (doc as { allowedIps?: string[] }).allowedIps ?? [],
          disabledAt: toDate((doc as { disabledAt?: Date | string | null }).disabledAt),
          bannedAt: toDate((doc as { bannedAt?: Date | string | null }).bannedAt),
          createdAt: toDate((doc as { createdAt?: Date | string }).createdAt) ?? new Date(),
          updatedAt: toDate((doc as { updatedAt?: Date | string }).updatedAt) ?? new Date(),
        };
      })
      .filter(Boolean) as any;
    const deleted = await prisma.authSecurityProfile.deleteMany();
    const created = data.length ? await prisma.authSecurityProfile.createMany({ data }) : { count: 0 };
    return { sourceCount: data.length, targetDeleted: deleted.count, targetInserted: created.count };
