"use client";

import { useQuery, useQueryClient, type UseQueryResult } from "@tanstack/react-query";
import { useEffect, useRef } from "react";

interface RealtimeConfig {
  queryKey?: readonly unknown[];
  interval?: number;
  enabled?: boolean;
  onUpdate?: (data: unknown) => void;
}

// Hook for real-time data updates with WebSocket fallback to polling
export function useRealtimeQuery<TData>(
  queryKey: readonly unknown[],
  queryFn: () => Promise<TData>,
  config?: RealtimeConfig
): UseQueryResult<TData, Error> {
  const queryClient = useQueryClient();
  const wsRef = useRef<WebSocket | null>(null);
  const intervalRef = useRef<NodeJS.Timeout | null>(null);

  const query = useQuery({
    queryKey,
    queryFn,
    enabled: config?.enabled !== false,
    refetchInterval: config?.interval || 30000, // Fallback polling
    refetchIntervalInBackground: true,
  });

  useEffect((): (() => void) => {
    if (config?.enabled === false) return (): void => {};

    // Try WebSocket connection first
    const wsUrl = `ws://localhost:3000/ws/${JSON.stringify(queryKey)}`;

    try {
      wsRef.current = new WebSocket(wsUrl);

      wsRef.current.onmessage = (event: MessageEvent): void => {
        try {
          const data = JSON.parse(event.data) as unknown;
          queryClient.setQueryData(queryKey as unknown[], data);
          config?.onUpdate?.(data);
        } catch (error) {
          console.warn('Failed to parse WebSocket data:', error);
        }
      };

      wsRef.current.onerror = (): void => {
        // Fallback to polling if WebSocket fails
        console.log('WebSocket failed, using polling fallback');
      };

    } catch (error) {
      // WebSocket not available, use polling
      console.log('WebSocket not available, using polling');
    }

    const currentInterval = intervalRef.current;
    return (): void => {
      if (wsRef.current) {
        wsRef.current.close();
      }
      if (currentInterval) {
        clearInterval(currentInterval);
      }
    };
  }, [queryKey, queryClient, config]);

  return query;
}

// Hook for server-sent events
export function useServerSentEvents<TData>(
  queryKey: readonly unknown[],
  endpoint: string,
  config?: { enabled?: boolean; onUpdate?: (data: TData) => void }
): void {
  const queryClient = useQueryClient();

  useEffect((): (() => void) => {
    if (config?.enabled === false) return (): void => {};

    const eventSource = new EventSource(endpoint);

    eventSource.onmessage = (event: MessageEvent): void => {
      try {
        const data = JSON.parse(event.data) as TData;
        queryClient.setQueryData(queryKey as unknown[], data);
        config?.onUpdate?.(data);
      } catch (error) {
        console.warn('Failed to parse SSE data:', error);
      }
    };

    eventSource.onerror = (error: Event): void => {
      console.warn('SSE connection error:', error);
    };

    return (): void => {
      eventSource.close();
    };
  }, [queryKey, endpoint, queryClient, config]);
}


"use client";

import { useQuery, useQueryClient, type Query } from "@tanstack/react-query";
import { useCallback } from "react";
import { fetchSettingsCached } from "@/shared/api/settings-client";

// Predefined cache strategies
export const cacheStrategies = {
  // For frequently changing data
  realtime: {
    staleTime: 0,
    gcTime: 1000 * 60, // 1 minute
    refetchOnWindowFocus: true,
    refetchOnReconnect: true,
  },

  // For moderately changing data
  standard: {
    staleTime: 1000 * 60 * 5, // 5 minutes
    gcTime: 1000 * 60 * 30, // 30 minutes
    refetchOnWindowFocus: true,
    refetchOnReconnect: true,
  },

  // For rarely changing data
  longTerm: {
    staleTime: 1000 * 60 * 60, // 1 hour
    gcTime: 1000 * 60 * 60 * 24, // 24 hours
    refetchOnWindowFocus: false,
    refetchOnReconnect: false,
  },

  // For static/configuration data
  static: {
    staleTime: Infinity,
    gcTime: 1000 * 60 * 60 * 24 * 7, // 1 week
    refetchOnWindowFocus: false,
    refetchOnReconnect: false,
  },
} as const;

// Hook for intelligent cache management
export function useSmartCache(): {
  optimizeCache: () => void;
  getCacheStats: () => { totalQueries: number; activeQueries: number; staleQueries: number; errorQueries: number; totalSize: number; avgSize: number };
  preloadCriticalData: (criticalQueries: Array<{ queryKey: unknown[]; queryFn: () => Promise<unknown> }>) => Promise<void>;
} {
  const queryClient = useQueryClient();

  const optimizeCache = useCallback((): void => {
    const cache = queryClient.getQueryCache();
    const queries = cache.getAll();

    queries.forEach((query: Query) => {
      const dataSize = JSON.stringify(query.state.data || {}).length;
      const lastAccessed = query.state.dataUpdatedAt;
      const observers = query.getObserversCount();

      // Remove large unused queries
      if (dataSize > 100000 && observers === 0 && 
          Date.now() - lastAccessed > 1000 * 60 * 10) { // 10 minutes
        cache.remove(query);
      }

      // Adjust stale time based on usage
      if (observers > 0) {
        if (typeof (query as any).setOptions === 'function') {
          (query as any).setOptions({
            staleTime: observers > 2 ? cacheStrategies.realtime.staleTime : 
                     cacheStrategies.standard.staleTime,
          });
        }
      }
    });
  }, [queryClient]);

  const getCacheStats = useCallback((): {
    totalQueries: number;
    activeQueries: number;
    staleQueries: number;
    errorQueries: number;
    totalSize: number;
    avgSize: number;
  } => {
    const cache = queryClient.getQueryCache();
    const queries = cache.getAll();

    const totalSize = queries.reduce((sum: number, query: Query) => {
      return sum + JSON.stringify(query.state.data || {}).length;
    }, 0);

    const activeQueries = queries.filter((q: Query) => q.getObserversCount() > 0).length;
    const staleQueries = queries.filter((q: Query) => q.isStale()).length;
    const errorQueries = queries.filter((q: Query) => q.state.status === 'error').length;

    return {
      totalQueries: queries.length,
      activeQueries,
      staleQueries,
      errorQueries,
      totalSize: Math.round(totalSize / 1024), // KB
      avgSize: Math.round(totalSize / (queries.length || 1) / 1024), // KB
    };
  }, [queryClient]);

  const preloadCriticalData = useCallback(async (criticalQueries: Array<{
    queryKey: unknown[];
    queryFn: () => Promise<unknown>;
  }>): Promise<void> => {
    const promises = criticalQueries.map(({ queryKey, queryFn }) =>
      queryClient.prefetchQuery({
        queryKey,
        queryFn,
        staleTime: cacheStrategies.longTerm.staleTime,
      })
    );

    await Promise.allSettled(promises);
  }, [queryClient]);

  return {
    optimizeCache,
    getCacheStats,
    preloadCriticalData,
  };
}

// Hook for cache warming strategies
export function useCacheWarming(): {
  warmUserSpecificData: (userId: string) => Promise<void>;
  warmNavigationData: (routes: string[]) => Promise<void>;
  warmFrequentlyAccessedData: () => Promise<void>;
} {
  const queryClient = useQueryClient();

  const warmUserSpecificData = useCallback(async (userId: string): Promise<void> => {
    const userQueries = [
      {
        queryKey: ['user', 'preferences', userId],
        queryFn: async (): Promise<any> => await fetch(`/api/user/${userId}/preferences`).then((r: Response) => r.json()),
      },
      {
        queryKey: ['user', 'settings', userId],
        queryFn: async (): Promise<any> => await fetch(`/api/user/${userId}/settings`).then((r: Response) => r.json()),
      },
    ];

    await Promise.allSettled(
      userQueries.map(({ queryKey, queryFn }) =>
        queryClient.prefetchQuery({ queryKey, queryFn })
      )
    );
  }, [queryClient]);

  const warmNavigationData = useCallback(async (routes: string[]): Promise<void> => {
    const navigationQueries = routes.map((route: string) => ({
      queryKey: ['navigation', route],
      queryFn: async (): Promise<any> => await fetch(`/api${route}`).then((r: Response) => r.json()),
    }));

    await Promise.allSettled(
      navigationQueries.map(({ queryKey, queryFn }) =>
        queryClient.prefetchQuery({ 
          queryKey, 
          queryFn,
          staleTime: cacheStrategies.standard.staleTime,
        })
      )
    );
  }, [queryClient]);

  const warmFrequentlyAccessedData = useCallback(async (): Promise<void> => {
    const frequentQueries = [
      {
        queryKey: ['settings', 'light'],
        queryFn: async (): Promise<any> => await fetchSettingsCached({ scope: "light" }),
      },
    ];

    await Promise.allSettled(
      frequentQueries.map(({ queryKey, queryFn }) =>
        queryClient.prefetchQuery({ 
          queryKey, 
          queryFn,
          staleTime: cacheStrategies.longTerm.staleTime,
        })
      )
    );
  }, [queryClient]);

  return {
    warmUserSpecificData,
    warmNavigationData,
    warmFrequentlyAccessedData,
  };
}

// Hook for query with automatic cache strategy selection
export function useAdaptiveQuery<T>(
  queryKey: unknown[],
  queryFn: () => Promise<T>,
  options?: {
    dataType?: 'realtime' | 'standard' | 'longTerm' | 'static';
    priority?: 'high' | 'medium' | 'low';
  }
): any {
  const dataType = options?.dataType || 'standard';
  const strategy = cacheStrategies[dataType];

  return useQuery({
    queryKey,
    queryFn,
    ...strategy,
    // Adjust based on priority
    staleTime: options?.priority === 'high' ? 
      Math.min(strategy.staleTime || 0, 1000 * 60) : // Max 1 minute for high priority
      strategy.staleTime,
  });
}

